var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이것은 대정화전쟁 이후 유래 없는 피해입니다.","JPN":"今回の被害の規模は、大浄化戦争以来最大だと言われています。","ENG":"This is the worst damage since the Grand Purification War.","TWN":"這是自大淨化戰爭以來前所未有的災難。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"먹구름은 물러갔으나 관리국마저 대처하지 못한 현 사태에 대해, 거주민 대다수가 상대적으로 안전한 관리구역으로 이주 절차를 신청한 것으로…","JPN":"墨雲は消えたものの、管理局ですら対処できなかった現状に対し、多くの居住者が比較的安全な管理区域への移住手続きを申し込んでおり……","ENG":"Though the dark clouds have cleared, the Administration failed to respond in time. Most residents have already applied to relocate to safer managed zones under its jurisdiction…","TWN":"墨雨雖然退去，但面對管理局都無法應對的現狀，大多數居民都申請了相對安全的管理區移民…"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"먹비가 그쳤군.","JPN":"墨雨が止んだな。","ENG":"The Ink Rain stopped.","TWN":"墨雨停了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관리국 덕에 도시는 최소한의 피해로 역경을 무사히 넘겼어.","JPN":"管理局のおかげで都市は被害を最小限に抑え、無事危機を乗り越えた。","ENG":"The city made it through with minimal damage.","TWN":"城市以最小的損失，平安度過了這次難關。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 아이가 먼 거리를 달려 우릴 찾아오지 않았다면… 우린 아직 도시에 이런 재난이 벌어진 줄도 몰랐겠지.","JPN":"あの子が遠い距離を走って私たちのところに来ていなかったら……いまだ都市に災害が訪れたことすら知らずにいただろう。","ENG":"If that girl hadn't run all that way to find us… We wouldn't have known a disaster had even struck in the city.","TWN":"如果那個孩子沒有跑到這麼遠的地方來找我們…我們可能還不知道城裡發生了這樣的災難。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"문득 궁금해지는군.","JPN":"突然気になってきたのだが。","ENG":"Makes me wonder.","TWN":"我突然感到好奇。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거를 바꾸어 세상에 먹비의 존재를 없앤다면, 오늘 있었던 일도 없던 것이 될지.","JPN":"過去を変えてこの世から墨雨を消し去ることができたら、今日の災害もなかったことになるのだろうか。","ENG":"If we manage to change the past and erase the Ink Rain from history, does that mean today's disaster never happened?","TWN":"如果改變過去，讓世界上不再有墨雨，那今天發生的災難也會變成沒發生過嗎？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그건 모를 일이지.","JPN":"それは分からないさ。","ENG":"Who knows?","TWN":"這就不知道了。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누구도 그렇게 해본 적이 없으니까.","JPN":"誰もやったことがないからな。","ENG":"No one's ever done it before.","TWN":"因為沒有人這麼做過。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"서연이 네가… 연구소 분들을 모셔왔다고? 그 다리로?","JPN":"シュエン、キミが……研究所の人たちをつれて来たの？　その脚で？","ENG":"Seoyeon… you brought the researchers here? With your legs?","TWN":"書妍，你…帶研究室的人過來的？用那雙腿？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"내가… 비 내리지 않는 곳으로 도망치라고 했잖아!","JPN":"ボクが……雨が降らない場所に逃げろって言っただろ！","ENG":"But… I told you to run away from the rain!","TWN":"我…不是叫你逃到沒有下雨的地方嗎！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"근데 왜 도망치지 않은 거야!","JPN":"なんですぐ逃げなかったんだよ！","ENG":"Why'd you go there?!","TWN":"但你為什麼去那裡！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"동월이 네가 모두를 도우려고 여기 남았으니까…","JPN":"トウゲツはみんなを助けるために残ったんだから……","ENG":"Just like you stayed behind to protect the kids at the orphanage, Dongwol…","TWN":"就像佟月為了保護保育院的孩子們而留下…"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"나도… 너한테 도움이 되고 싶었어.","JPN":"アタシも、キミの力になりたかった。","ENG":"I never planned to run away either.","TWN":"我從一開始就沒想過要逃跑。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"도망치는 것보다 더 중요한 게… 여기 있으니까.","JPN":"逃げるより……もっと大事なものがあったから。","ENG":"Some things… matter more than running.","TWN":"因為…有比逃跑更重要的事情。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"그래서 다행이야.","JPN":"だからよかった。","ENG":"That's why I'm relieved.","TWN":"所以太好了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"네가 무사해서.","JPN":"トウゲツが無事で、よかったよ。","ENG":"I'm relieved you're safe.","TWN":"你平安無事，真是太好了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"그치만 나 때문에 네 눈이…","JPN":"うっ……ボクのせいでシュエンの目が……","ENG":"*Sniffle…* Because of me, your eyes…","TWN":"嗚…都怪我，你的眼睛…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"왜… 그런 거야! 왜 나 때문에 네가…!","JPN":"なんで……なんでだ！　なんでボクのせいでシュエンが……！","ENG":"Why'd you do it…?! Because of me…!","TWN":"為什麼…會這樣！為什麼你為了我…！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"네 얼굴… 만져봐도 돼?","JPN":"顔……触ってもいい？","ENG":"Can I… touch your face?","TWN":"你的臉…可以讓我摸摸嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"나 때문이야… 내가 널 지켜줄 수만 있었어도…","JPN":"ボクのせいだ……ボクが、シュエンを守れたら……","ENG":"If I… could've just protected you…","TWN":"都怪我…如果我能保護你…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};